const fs = require('fs');
const path = require('path');

const filePath = $json.path;
const filename = path.basename(filePath);

// Validate: must be .txt and start with YYYY-MM-DD
if (!filename.endsWith('.txt') || !/^\d{4}-\d{2}-\d{2}/.test(filename)) {
  return [];
}

const datePrefix = filename.match(/^\d{4}-\d{2}-\d{2}/)[0];
const chatText = fs.readFileSync(filePath, 'utf8');

return {
  json: {
    filename,
    filePath,
    chatText,
    datePrefix
  }
};

const fs = require('fs');
const datePrefix = $json.datePrefix;
const outputDir = `/home/node/output/${datePrefix}`;
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}
return {
  json: {
    ...$json,
    outputDir
  }
};

